sp_widget.client_script:
function($scope, spModal, $rootScope, spUtil) {
	// STRY0079658 removed dtBreadcrumbs since this is always used in a a page by itself or in modal
	var c = this;
	$scope.submitting = false;
	var g_form;
	if (c.data.currentStep == undefined){
		c.data.currentStep = 'selectTemplate';
	}
	// NOTE:  I could use a different click here.  I could use data table without tasker data table
	// ISSUE: the Tasker DataTable, if you go to the 
	$scope.$on("data_table.click", function(evt, e) {
		c.data.selected_Template_id = e.sys_id;
  });
	c.changeTemplateLevel = function(){
		var o="";
		var d="";
		var table = "x_153465_discovert_discover_routing_template";
		var filter = "";
		var view = "";
		var title = "";
		switch (c.data.templateLevel) {
			case "all":
				title = "Any";
				filter = c.data.allFilter;
				view = "OUProcess";
				break;
			case "global":
				title = "a Global";
				filter = c.data.globalFilter;
				view = "GlobalProcess";			
				break;
			case "organizationalunit":
				title = "an OU";
				// TODO, LOOK UP THE OUs FOR THIS USER
				filter = c.data.ouFilter;
				view = "OUProcess";
				break;
			case "personal":
				title = "a Personal";
				filter = c.data.myFilter;
				view = "myprocess";			
				break;
			default:
				filter = "";
		}

		var params = {
			o: o,
			d: d,
			table: table,
			filter: filter,
			view: view, 
			title: "Select " + title + " Template to Start",
			open_row_details_in_modal: false,
			window_size : "10"
		};
		spUtil.get('discovertasker-widget-data-table',params).then(function(response){
			c.data.templateListWidget = response;
		})		
	}
	$scope.btnCancelClick = function(){
		// close modal window
		$scope.$parent.buttonClicked($scope.$parent.options.buttons[0]);
	}
	$scope.btnBackClick = function(){
		// go back to selection page
		c.data.selected_Template_id = '';
		c.data.currentStep = 'selectTemplate';
		c.changeTemplateLevel();
	}

	$scope.btnNextButton = function(){
		if(c.data.selected_Template_id=='' || c.data.selected_Template_id== undefined){
			alert('Please select the Template to run.');
		} else{
			c.data.currentStep = 'enterInfo';
			c.server.update();
		}
	}	

	// STRY0123152
	$scope.btnGenderateDraftButton = function(){
		startTemplate('generate_draft');
	}
	$scope.btnStartButton = function(){
		startTemplate('start_template');
	}

	function startTemplate(action){
			if(g_form){
				$scope.submitting = true;
				if(g_form.submit(action)){
					$(".showAlert").hide().show('medium');
					c.data.currentStep = 'StartTemplate';
				}
				$scope.submitting = false;
			}
	}

	angular.element('.modal-footer').css({display:'none'});  
	// STRY0100724: DEV Story- Performance Improvements -  Running Templates and implify
	function initForm(gFormInstance) {
		if (gFormInstance.getTableName() != undefined &&
				gFormInstance.getTableName() == $scope.data.f.table) {
			g_form = gFormInstance;
		}
	}

	$scope.$on('spModel.gForm.env.created', function(e, gFormInstance) {
		initForm(gFormInstance);
	});

}

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.09.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------


.iconlink a label,h2 {
  display: block;
  font-size: 1em;
  font-weight: 300;
  line-height: 1.1;
  padding: 0;
  margin: 0 0 10px 0;
  cursor: pointer;
}



//------------------------------------------------------------------------------------------------------------------------
// CUSTOM
//------------------------------------------------------------------------------------------------------------------------


/* SECTIONS & FORMS */
//------------------------------------------------------------------------------------------------------------------------
.ng-isolate-scope .h4.ng-binding{
  font-weight: 400 !important;
  font-family: "SourceSansPro", Helvetica, Arial, sans-serif; //'Lucida Sans Unicode';
  padding-left: 5px;
	border-left-style: solid;
	border-left-color: $primary;
	border-left-width: 5px;
	color: $primary;
	padding-top: 8px;
	padding-bottom: 5px;
}

fieldset.ng-scope{
  margin-top: 5px;
}

label{
	//font-weight: 100!important;
  color: $primary;
}


/* DURATION */
//------------------------------------------------------------------------------------------------------------------------

#dur-minutes,
#dur-seconds { 
  visibility: hidden!important;
}

#dur-days,
#dur-hours { 
  width: 40px!important
}


//------------------------------------------------------------------------------------------------------------------------
// OOTB FORM WIDGET
//------------------------------------------------------------------------------------------------------------------------


.btn-form-menu {
	vertical-align: inherit;
  padding: inherit;
  background: none;
}

.panel-title {
  word-wrap: break-word;
}

.panel-heading {
  .dropdown-menu {
    a {
      white-space: normal;
    }
  }
}

/*
2.7.0 | 2021-10-29 | mmcc | STRY0110472 - Stretch- 508 Compliant- Delete Buttons- (ALL Red buttons)
.dtech-field-error-label {} replaces below; Find it in Tasker Theme > Tasker Form Error Overrides Style Sheet
This widget is not using the below CSS selector
.sc-field-error-label {
  margin-right: .5em;
  display: inline-block;
  background-color: $sc-field-error-color;
}
*/

.comment {
	font-weight: bold;
	margin-top: 2px;
	margin-bottom: 2px;
}
.mce-panel, .mce-btn {
	background-image: none;
	background-color: #f0f3f4;
}

.action-btn {
  margin-right: 5px;
}

.timeline-container {
   max-height: 50vh;
   height: 100%;
   overflow-y: auto;
}

.panel .panel {
    height: auto !important;
}

.attachment-button {
  .glyphicon-paperclip {
    font-size: 18px;
  }
}

.dropdown {
  .glyphicon-menu-hamburger:focus {
 		outline: thin dotted;
		outline: 5px auto $input-border-focus;
		outline-offset: -2px; 
	}
}

.empty-state-wrapper {
  width: 100%;
  height: 100%;
  align-items: center;
  display: flex;
  flex-direction: column;
  padding: 10vh 20px 20px;

  .empty-state {
    border: 1px solid #e7e9eb;
    border-radius: 10px;
    max-width: 700px;
    padding: 30px 40px 20px;
    position: relative;

    .empty-state-badge {
      top: -36px;
      left: 50%;
      position: absolute;
      height: 72px;
      width: 72px;
      -webkit-align-items: center;
      -ms-flex-align: center;
      align-items: center;
      border-radius: 100%;
      color: #ffffff;
      display: -webkit-flex;
      display: -ms-flexbox;
      display: flex;
      font-size: 40px;
      -webkit-justify-content: center;
      -ms-flex-pack: center;
      justify-content: center;
      margin-left: -36px;
      text-align: center;
    }

    .empty-state-header {
      font-size: 30px;
      text-align: center;
      color: #343d47;
    }

    .empty-state-content {
      ul {
        list-style: disc outside;
        margin: 0 0 10px 0;
        padding: 0 0 0 30px;
      }
    }
  }
}

.text-success-alt {
	background-color: $state-success-text;
}

.text-info-alt {
	background-color: $state-info-text;
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: TASKER DATA TABLE
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: Rob Joy
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 07.05.2021 | raj | STRY0100724: DEV Story- Performance Improvements -  Running Templates and implify
//                                   Updates in Server, Client and HTML
// 2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
// 											In CSS, selector .taskform-classification-banner removed, not used. 
// 											 Selector .assignmentgroup-banner removed, not used.
//											 Selector #sp_formfield_status removed, was commented out.
//											In Server script, fixed white space issues, format whole script.
//                                          Changes in CSS and Server script
// 2.7.0 | 2021-10-29 | mmcc | STRY0110472 - Stretch- 508 Compliant- Delete Buttons- (ALL Red buttons) 
//											In CSS, Comment out unused .sc-field-error-label.
//                                          Changes in CSS
// 2.7.0 | 2021-10-230 | raj | STRY0113375 - Draft from Templates Update- UI- Add "Draft Template" Action Button
//											In HTML,updated button text and hover
//											NOTE: caption and hover should pick up from UI Actions, but don't
// 2.8.0 | 2022-06-02 | raj | STRY0123152 - Draft Tasks- Selecting "Run Template" from 'Draft Tasks' only generates 'Drafts Tasks'
//											Changes in Server Script, Client Controller and HTML
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp) {
    // STRY0079658 added $sp to get the parentTask off of the URL on mobile
    /* populate the 'data' object */
    /* e.g., data.table = $sp.getValue('table'); */
    data.templateLevel = (input || {}).templateLevel || 'all';
    data.parentTask = (input || {}).parentTask || (options || {}).parentTask || $sp.getParameter('parentTask');
    // STRY0100724
    data.selected_Template_id = (input || {}).selected_Template_id || (options || {}).selected_Template_id || $sp.getParameter('selected_Template_id');
    // STRY0098385 - remove Cancel button from Mobile 
    data.page_id = $sp.getParameter("id");

    var widgetParams = {};
    var taskingScripts = new tasking_System_Settings_Scripts();
    // STRY0079658 added parent task to get restricted group
    var templateFilters = taskingScripts.getTemplateFilters(true, data.parentTask);

    data.userHasPersonalTemplateRights = templateFilters.hasMyTemplateRights + '';
    // if the user has personal template permissions, they can run personal templates
    data.userHasOUTemplateRights = templateFilters.hasOUTemplateRights + '';
    // if user is a Task Administrator, they can run Global Templates
    data.userHasGlobalTemplateRights = templateFilters.hasGlobalTemplateRights + '';
    data.allFilter = templateFilters.allTemplateFilter;
    data.myFilter = templateFilters.myTemplateFilter;
    data.ouFilter = templateFilters.ouFilter;
    data.globalFilter = templateFilters.globalFilter;
    data.f = {};

		// STRY0123152
		if(data.parentTask){
			var gr_Parent = new GlideRecord("x_153465_discovert_route_task_instance");
			if(gr_Parent.get(data.parentTask)){
				if(gr_Parent.state==-6){
					data.draftOnly = true;
				}
			}
		}

    // initial load, build the original data table widget
    // STRY0097161
    if (input == undefined || input.currentStep == undefined) {
        var table = "x_153465_discovert_discover_routing_template";
        var filter = "";
        var view = "OUProcess";
        var o = "";
        var d = "";
        widgetParams = {
            o: o,
            d: d,
            table: table,
            filter: data.allFilter,
            view: view,
            title: "Select Template to Start",
            open_row_details_in_modal: false,
            window_size: 10
        };
        data.widgetParams = widgetParams;
        data.templateListWidget = $sp.getWidget('discovertasker-widget-data-table', widgetParams);
    } else if (input.currentStep == 'enterInfo') {
        data.canAttach = false;
        // build the Template Instance Form here
        data.f = $sp.getForm("x_153465_discovert_discover_routing_runtime",
            "-1", 'parent_task=' + data.parentTask + '^routing_template_ref=' + data.selected_Template_id, "Default View");
        data.canRun = new uiConditionCheck().startTemplateUIAction(data.selected_Template_id, data.parentTask);
    }
})($sp);
